import Layout from '../components/layout';

import {graphql, useStaticQuery} from 'gatsby';
import * as React from 'react';
import Tabs from '@mui/material/Tabs';
import Tab from '@mui/material/Tab';
import Box from '@mui/material/Box';
import Typography from '@mui/material/Typography';
import Divider from '@mui/material/Divider';
import Paper from '@mui/material/Paper';
import Grid from '@mui/material/Unstable_Grid2';
import Breadcrumbs from '@mui/material/Breadcrumbs';
import Link from '@mui/material/Link';
import Seo from '../components/seo';

import ImageList from '@mui/material/ImageList';
import ImageListItem from '@mui/material/ImageListItem';

const Desc = ({data}) => {
  let html = data.desc.data.childMarkdownRemark.html;
  data.desc.medias.forEach(item => {
    const reg = new RegExp(`(<img src="${item.src}".*?">)`, 'g');
    html = html.replaceAll(reg,
        `<div class="image-wrapper"><img src="${item.localFile.publicURL}"></div>`);
  });
  return (<Grid md={12} xs={12} sx={{mx: {md: 2, xs: 1}}} className="markdown"
                dangerouslySetInnerHTML={{__html: html}}></Grid>);
};

const Photo=({data})=>{

 return (    <Box sx={{ overflowY: 'scroll',mx:2 }}>
   <ImageList variant="masonry" cols={3} gap={8}>
     {data.map((item,index) => (
         <ImageListItem key={index}>
           <img
               src={`${item.image.localFile.publicURL}`}
               srcSet={`${item.image.localFile.publicURL}`}
               alt={item.name}
               loading="lazy"
           />
         </ImageListItem>
     ))}
   </ImageList>
 </Box>)
}

const About = () => {
      const [value, setValue] = React.useState('desc');

      const {strapiCorporateDesc,allStrapiCorporatePhoto} = useStaticQuery(graphql`
 query CorporateDescQuery {
   allStrapiCorporatePhoto {
    nodes {
      name
      image {
        localFile {
          publicURL
        }
      }
    }
  }
    strapiCorporateDesc {
    desc {
      data {
        childMarkdownRemark {
          html
        }
      }
      medias {
        localFile {
          publicURL
        }
        src
      }
    }
  }
}
  `);

      const handleChange = (event, newValue) => {
        setValue(newValue);
      };
      const pages = [
        {id: 'desc', text: '公司介绍'},
        {id: 'photo', text: '基地面貌'},
      ];
      return (<Layout>
        <Box sx={{mt: 1}}>
          <Paper elevation={2} sx={{mr: 2, ml: 2}}>
            <Breadcrumbs sx={{pt: 2, pb: 4, pl: 2, pr: 2}} aria-label="breadcrumb">
              <Link underline="hover" color="inherit" href="/">
                首页
              </Link>
              <Typography color="text.primary">关于我们</Typography>
            </Breadcrumbs>
            <Tabs
                value={value}
                onChange={handleChange}
                variant="scrollable"
                scrollButtons
                allowScrollButtonsMobile
                aria-label="scrollable force tabs example"
            >
              {pages.map((item, index) => {
                return <Tab key={item.id} value={item.id} label={item.text}/>;
              })}
            </Tabs>
            <Divider/>
            <Grid container  spacing={0.5} sx={{mx:2}}>
              {value === 'desc' && <Desc data={strapiCorporateDesc}></Desc>}
              {value === 'photo' && <Photo data={allStrapiCorporatePhoto.nodes}></Photo>}
            </Grid>

          </Paper>
        </Box>
      </Layout>);
    }
;
export const Head = () => <Seo title="关于我们"/>;
export default About;
